import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛鬘 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    嚴先: true,
    臂(bi, 筆) {
        const { M, C, Qk, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
        const { dot } = bi;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-7.6, 36.6], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.1], [7.6, 36.6], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        // 華鬘：兩端垂於拳，中垂如綬（花珠連綴）
        衣(() => {
            M(-5.4, 34.8);
            C(-2.0, 36.6, 2.0, 36.6, 5.4, 34.8);
            S();
            M(-5.4, 35.6);
            C(-2.0, 37.5, 2.0, 37.5, 5.4, 35.6);
            S();
            細(() => {
                for (const t of [-3.6, -1.8, 0, 1.8, 3.6]) {
                    if (Math.abs(t) > 2)
                        dot(t, 35.75 + (1 - Math.abs(t) / 5.4) * 0.9, 0.24);
                    else {
                        const cz = 36.35 + (1 - Math.abs(t) / 5.4) * 0.55;
                        M(t - 0.28, cz - 0.28);
                        Qk(t, cz + 0.15, t + 0.28, cz - 0.28);
                        S();
                    }
                }
            });
            // 綬尾：兩端小垂
            逸(() => {
                M(-5.6, 35.9);
                C(-6.0, 37.4, -5.6, 38.8, -6.0, 40.2);
                S();
                M(5.6, 35.9);
                C(6.0, 37.4, 5.6, 38.8, 6.0, 40.2);
                S();
            });
        });
        // 兩拳執鬘端（蔽法自斷鬘線）
        側拳(bi, -6.4, 35.3, 0.5, 1.1);
        側拳(bi, 6.4, 35.3, -0.5, 1.1, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-8.5, 36.0, -7.9, 37.1, -8.5, 38.3], [-7.7, 35.8, -7.1, 36.9, -7.7, 38.1]], [-7.9, 37.0]);
            腕釧(bi, [[8.5, 36.0, 7.9, 37.1, 8.5, 38.3], [7.7, 35.8, 7.1, 36.9, 7.7, 38.1]], [7.9, 37.0]);
        });
    },
});
